// HierarchicalSampler is the day-one Sampler: recursive weighted draw
// over the project's module tree with an anti-coverage bias. Fractal
// by construction — the same weighted-subdivision rule applies at
// every depth.
type HierarchicalSampler struct {
	AntiCoverageWeight float64
	SizeWeightExp      float64
}

func (h *HierarchicalSampler) Name() string { return "hierarchical-v1" }

func (h *HierarchicalSampler) Next(out *BoundaryOutput, covered map[string]bool, k int, rng *rand.Rand) []string {
	if k <= 0 || out == nil || len(out.Chunks) == 0 {
		return nil
	}
	aw := h.AntiCoverageWeight
	if aw <= 0 {
		aw = 3.0
	}
	sw := h.SizeWeightExp
	if sw <= 0 {
		sw = 0.5
	}
	moduleChunks := make(map[string][]Chunk, len(out.Modules))
	for _, c := range out.Chunks {
		moduleChunks[c.ModuleID] = append(moduleChunks[c.ModuleID], c)
	}
	moduleIDs := make([]string, 0, len(moduleChunks))
	for id, chs := range moduleChunks {
		sort.Slice(chs, func(i, j int) bool { return chs[i].ID < chs[j].ID })
		moduleChunks[id] = chs
		moduleIDs = append(moduleIDs, id)
	}
	sort.Strings(moduleIDs)
	drawn := make(map[string]bool)
	picked := make([]string, 0, k)
	for i := 0; i < k; i++ {
		weights := make([]float64, len(moduleIDs))
		total := 0.0
		for mi, mid := range moduleIDs {
			uncoveredEff := 0
			uncoveredChunks := 0
			totalChunks := 0
			for _, c := range moduleChunks[mid] {
				totalChunks++
				if covered[c.ID] || drawn[c.ID] {
					continue
				}
				uncoveredEff += c.EffLines
				uncoveredChunks++
			}
			if uncoveredChunks == 0 {
				continue
			}
			frac := float64(uncoveredChunks) / float64(totalChunks)
			sizeTerm := math.Pow(float64(uncoveredEff), sw)
			if uncoveredEff == 0 {
				sizeTerm = 1.0
			}
			w := sizeTerm * (1.0 + aw*frac)
			weights[mi] = w
			total += w
		}
		if total <= 0 {
			break
		}
		u := rng.Float64() * total
		chosen := ""
		cum := 0.0
		for mi, mid := range moduleIDs {
			if weights[mi] == 0 {
				continue
			}
			cum += weights[mi]
			if u < cum {
				chosen = mid
				break
			}
		}
		if chosen == "" {
			break
		}
		avail := make([]string, 0, len(moduleChunks[chosen]))
		for _, c := range moduleChunks[chosen] {
			if covered[c.ID] || drawn[c.ID] {
				continue
			}
			avail = append(avail, c.ID)
		}
		if len(avail) == 0 {
			continue
		}
		idx := rng.Intn(len(avail))
		drawn[avail[idx]] = true
		picked = append(picked, avail[idx])
	}
	return picked
}

func TestSampler_DeterministicSequence(t *testing.T) {
	out := synthBoundary(5, 10, 20)
	covered := map[string]bool{}
	s := &HierarchicalSampler{}
	var seq1, seq2 []string
	rng1 := rand.New(rand.NewSource(42))
	for i := 0; i < 10; i++ {
		seq1 = append(seq1, s.Next(out, covered, 4, rng1)...)
	}
	rng2 := rand.New(rand.NewSource(42))
	for i := 0; i < 10; i++ {
		seq2 = append(seq2, s.Next(out, covered, 4, rng2)...)
	}
	if len(seq1) != len(seq2) {
		t.Fatalf("sequences differ in length: %d vs %d", len(seq1), len(seq2))
	}
	for i := range seq1 {
		if seq1[i] != seq2[i] {
			t.Errorf("sequence drift at %d: %q vs %q", i, seq1[i], seq2[i])
		}
	}
}

func TestSampler_RespectsCovered(t *testing.T) {
	out := synthBoundary(3, 4, 10)
	covered := map[string]bool{}
	for _, c := range out.Chunks {
		if c.ModuleID == "mod-0" {
			covered[c.ID] = true
		}
	}
	s := &HierarchicalSampler{}
	rng := rand.New(rand.NewSource(1))
	for i := 0; i < 50; i++ {
		picks := s.Next(out, covered, 4, rng)
		for _, id := range picks {
			if strings.HasPrefix(id, "mod-0-chunk-") {
				t.Errorf("covered module-0 chunk drawn: %s", id)
			}
		}
	}
}

import { useEffect, useState } from 'react';
import { Article, fetchArticles, deleteArticle } from '../lib/api';
import { Spinner } from './Spinner';
import { ConfirmDialog } from './ConfirmDialog';

export interface ArticleListProps {
  authorId?: number;
  onSelect?: (article: Article) => void;
}

export function ArticleList({ authorId, onSelect }: ArticleListProps) {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [pendingDelete, setPendingDelete] = useState<Article | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    fetchArticles({ authorId })
      .then((items) => {
        if (cancelled) return;
        setArticles(items);
        setError(null);
      })
      .catch((err) => {
        if (cancelled) return;
        setError(err.message ?? 'unknown error');
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, [authorId]);

  if (loading) return <Spinner />;
  if (error) return <div className="error">Failed to load articles: {error}</div>;

  return (
    <ul className="article-list">
      {articles.map((a) => (
        <li key={a.id} onClick={() => onSelect?.(a)}>
          <h3>{a.title}</h3>
          <p>{a.snippet}</p>
          <button onClick={() => setPendingDelete(a)}>Delete</button>
        </li>
      ))}
      {pendingDelete && (
        <ConfirmDialog
          message={`Delete “${pendingDelete.title}”?`}
          onConfirm={async () => {
            await deleteArticle(pendingDelete.id);
            setArticles((cur) => cur.filter((x) => x.id !== pendingDelete.id));
            setPendingDelete(null);
          }}
          onCancel={() => setPendingDelete(null)}
        />
      )}
    </ul>
  );
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, waitFor, fireEvent } from '@testing-library/react';
import { ArticleList } from './ArticleList';
import * as api from '../lib/api';

vi.mock('../lib/api');
const mockedFetch = vi.mocked(api.fetchArticles);
const mockedDelete = vi.mocked(api.deleteArticle);

beforeEach(() => {
  vi.resetAllMocks();
});

describe('ArticleList', () => {
  it('renders articles after load', async () => {
    mockedFetch.mockResolvedValueOnce([
      { id: 1, title: 'Hello', snippet: 'world', authorId: 5 },
    ]);
    render(<ArticleList />);
    await waitFor(() => expect(screen.getByText('Hello')).toBeInTheDocument());
  });

  it('shows an error on fetch failure', async () => {
    mockedFetch.mockRejectedValueOnce(new Error('boom'));
    render(<ArticleList />);
    await waitFor(() => expect(screen.getByText(/Failed to load articles/)).toBeInTheDocument());
  });

  it('confirms deletion before removing', async () => {
    mockedFetch.mockResolvedValueOnce([
      { id: 1, title: 'A', snippet: 's', authorId: 1 },
    ]);
    mockedDelete.mockResolvedValueOnce(undefined);
    render(<ArticleList />);
    await waitFor(() => screen.getByText('A'));
    fireEvent.click(screen.getByText('Delete'));
    fireEvent.click(screen.getByText('OK'));
    await waitFor(() => expect(mockedDelete).toHaveBeenCalledWith(1));
  });
});
